class Solution {
public:
    int binaryGap(int n) {
        int maxGap = 0, prevOne = -1;
        while (n) {
            if (n & 1) {
                if (prevOne != -1) {
                    maxGap = max(maxGap, prevOne - i);
                }
                prevOne = i;
            }
            n >>= 1;
            i++;
        }
        return maxGap;
    }
};
